&lt;li style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot; data-stringify-indent=&quot;0&quot; data-stringify-border=&quot;0&quot;&gt;&lt;span style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;California (outside of San Francisco Bay Area): $46.25&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot; data-stringify-indent=&quot;0&quot; data-stringify-border=&quot;0&quot;&gt;&lt;span style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;Colorado: $42.50&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot; data-stringify-indent=&quot;0&quot; data-stringify-border=&quot;0&quot;&gt;&lt;span style=&quot;font-size: 12pt; font-family: helvetica, arial, sans-serif;&quot;&gt;Utah, Arizona, and North Carolina: $40.00&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;
